"use client";

import { useState, useEffect, useRef } from "react";
import { createClient } from "@/utils/supabase/client";
import { useUserStore, UserRole } from "@/lib/userStore";
import { User, Building2, ArrowLeft, Eye, EyeOff, Lock, Mail } from "lucide-react";
import { gsap } from "gsap";
import { useRouter } from "next/navigation";
import { toast } from "sonner";

export default function LoginPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [authMode, setAuthMode] = useState<"login" | "signup">("login");
    const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
    const [step, setStep] = useState<"role" | "auth">("role");

    const { setRole, role, syncProfile } = useUserStore();
    const supabase = createClient();
    const router = useRouter();

    const mainRef = useRef<HTMLElement>(null);
    const formRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const checkExistingSession = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (session) {
                await syncProfile(supabase);
                router.push("/dashboard");
            }
        };
        checkExistingSession();
        router.prefetch("/dashboard");
    }, [router, supabase.auth, syncProfile]);

    useEffect(() => {
        const animateItems = mainRef.current?.querySelectorAll('.animate-item');
        if (animateItems && animateItems.length > 0) {
            const tl = gsap.timeline({ defaults: { ease: "expo.out" } });
            tl.fromTo(animateItems,
                { y: 30, opacity: 0 },
                { y: 0, opacity: 1, stagger: 0.1, duration: 1.5, delay: 0.2 }
            );
        }
    }, [step]);

    useEffect(() => {
        if (formRef.current && step === "auth") {
            gsap.fromTo(formRef.current,
                { opacity: 0, x: 20 },
                { opacity: 1, x: 0, duration: 0.8, ease: "power3.out" }
            );
        }
    }, [authMode, step]);

    const handleRoleSelect = (selectedRole: UserRole) => {
        setRole(selectedRole);
        setStep("auth");
    };

    const handleAuth = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!email || !password) return;

        setStatus("loading");

        if (authMode === "login") {
            const { error } = await supabase.auth.signInWithPassword({
                email,
                password,
            });

            if (error) {
                console.error("LOGIN_ERROR:", error);
                setStatus("error");
                toast.error("LOGIN FAILED", {
                    description: error.message
                });
                return;
            } 
            
            setStatus("success");
            toast.success("Authentication confirmed. Redirecting to dashboard...");
            router.push("/dashboard");
        } else {
            const { error } = await supabase.auth.signUp({
                email,
                password,
                options: {
                    data: {
                        role: role
                    }
                }
            });

            if (error) {
                setStatus("error");
                toast.error("INITIALIZATION FAILED", {
                    description: error.message
                });
            } else {
                setStatus("success");
                toast.success("IDENTITY LOGGED", {
                    description: "Please check your inbox for the secure confirmation link."
                });
                setTimeout(() => setAuthMode("login"), 2000);
            }
        }
    };

    return (
        <div className="relative w-full min-h-screen flex flex-col items-center justify-center overflow-hidden">
            <main ref={mainRef} className="relative z-10 flex flex-col items-center w-full max-w-md px-8 py-20">
                <div className="mb-12 text-center w-full animate-item">
                    <h1 className="text-white text-4xl font-black tracking-[0.2em] uppercase mb-2 drop-shadow-2xl">
                        {authMode === "login" ? "Sign In" : "Register"}
                    </h1>
                    <div className="h-[1px] w-full bg-gradient-to-r from-transparent via-emerald-500/50 to-transparent" />
                    <p className="text-neutral-500 text-[10px] tracking-[0.3em] uppercase mt-4 font-bold">
                        {step === "role" ? "Choose Account Type" : `${role || 'Secure'} Account Verification`}
                    </p>
                </div>

                {step === "role" ? (
                    <div className="grid grid-cols-1 gap-4 w-full">
                        <button
                            onClick={() => handleRoleSelect("freelancer")}
                            className="glass-panel p-6 flex items-center gap-4 border border-white/5 hover:border-emerald-500/50 transition-all group text-left animate-item"
                        >
                            <div className="p-4 rounded-full bg-emerald-500/10 text-emerald-500 group-hover:bg-emerald-500 group-hover:text-white transition-all shadow-[0_0_20px_rgba(16,185,129,0.1)] group-hover:shadow-[0_0_30px_rgba(16,185,129,0.4)]">
                                <User className="w-6 h-6" />
                            </div>
                            <div>
                                <h3 className="text-white font-bold tracking-widest uppercase text-sm">Freelancer</h3>
                                <p className="text-neutral-500 text-[10px] mt-1 uppercase tracking-tight">Access global project directory</p>
                            </div>
                        </button>

                        <button
                            onClick={() => handleRoleSelect("organization")}
                            className="glass-panel p-6 flex items-center gap-4 border border-white/5 hover:border-blue-500/50 transition-all group text-left animate-item"
                        >
                            <div className="p-4 rounded-full bg-blue-500/10 text-blue-500 group-hover:bg-blue-500 group-hover:text-white transition-all shadow-[0_0_20px_rgba(59,130,246,0.1)] group-hover:shadow-[0_0_30px_rgba(59,130,246,0.4)]">
                                <Building2 className="w-6 h-6" />
                            </div>
                            <div>
                                <h3 className="text-white font-bold tracking-widest uppercase text-sm">Organization</h3>
                                <p className="text-neutral-500 text-[10px] mt-1 uppercase tracking-tight">Deploy contracts & hire talent</p>
                            </div>
                        </button>
                    </div>
                ) : (
                    <div className="w-full" ref={formRef}>
                        {status === "success" && authMode === "signup" ? (
                            <div className="glass-panel w-full p-10 text-center flex flex-col items-center justify-center animate-item">
                                <div className="w-16 h-16 rounded-full border-2 border-emerald-500/30 flex items-center justify-center mb-6 shadow-[0_0_30px_rgba(16,185,129,0.2)]">
                                    <div className="w-3 h-3 rounded-full bg-emerald-400 animate-pulse" />
                                </div>
                                <h2 className="text-white text-xl font-bold tracking-[0.2em] mb-3">ACCOUNT CREATED</h2>
                                <p className="text-neutral-400 text-xs leading-relaxed uppercase tracking-widest">
                                    Signup complete. Proceeding to login...
                                </p>
                            </div>
                        ) : (
                            <div className="w-full relative group">
                                <button
                                    onClick={() => setStep("role")}
                                    className="absolute -top-12 left-0 text-neutral-500 hover:text-white flex items-center gap-2 text-[9px] uppercase tracking-[0.3em] transition-all font-black"
                                >
                                    <ArrowLeft className="w-3 h-3" /> [ Back ]
                                </button>

                                <form onSubmit={handleAuth} className="space-y-4">
                                    <div className="relative group">
                                        <div className="absolute -inset-0.5 bg-gradient-to-r from-emerald-500/20 to-blue-500/20 rounded-xl blur opacity-30 group-focus-within:opacity-100 transition duration-1000" />
                                        <div className="relative flex items-center bg-[#0a0a0c]/80 backdrop-blur-3xl border border-white/10 rounded-xl overflow-hidden shadow-2xl">
                                            <div className="pl-6 text-neutral-500 group-focus-within:text-emerald-500 transition-colors">
                                                <Mail className="w-4 h-4" />
                                            </div>
                                            <input
                                                type="email"
                                                value={email}
                                                onChange={(e) => setEmail(e.target.value.trim())}
                                                placeholder="EMAIL_IDENTIFIER"
                                                className="w-full bg-transparent text-white font-mono text-xs tracking-[0.2em] outline-none py-6 px-6 placeholder:text-neutral-700 uppercase"
                                                required
                                                disabled={status === "loading"}
                                            />
                                        </div>
                                    </div>

                                    <div className="relative group">
                                        <div className="absolute -inset-0.5 bg-gradient-to-r from-emerald-500/20 to-blue-500/20 rounded-xl blur opacity-30 group-focus-within:opacity-100 transition duration-1000" />
                                        <div className="relative flex items-center bg-[#0a0a0c]/80 backdrop-blur-3xl border border-white/10 rounded-xl overflow-hidden shadow-2xl">
                                            <div className="pl-6 text-neutral-500 group-focus-within:text-blue-500 transition-colors">
                                                <Lock className="w-4 h-4" />
                                            </div>
                                            <input
                                                type={showPassword ? "text" : "password"}
                                                value={password}
                                                onChange={(e) => setPassword(e.target.value)}
                                                placeholder="SECURE_PASSPHRASE"
                                                className="w-full bg-transparent text-white font-mono text-xs tracking-[0.2em] outline-none py-6 px-6 placeholder:text-neutral-700"
                                                required
                                                disabled={status === "loading"}
                                            />
                                            <button
                                                type="button"
                                                onClick={() => setShowPassword(!showPassword)}
                                                className="pr-6 text-neutral-600 hover:text-white transition-colors"
                                            >
                                                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>

                                    <button
                                        type="submit"
                                        disabled={status === "loading" || !email || !password}
                                        className="w-full py-6 bg-emerald-500/10 hover:bg-emerald-500 text-emerald-400 hover:text-white text-[11px] font-black tracking-[0.4em] uppercase transition-all border border-emerald-500/20 hover:border-emerald-400 rounded-xl disabled:opacity-30 shadow-[0_0_30px_rgba(16,185,129,0.1)] hover:shadow-[0_0_40px_rgba(16,185,129,0.3)]"
                                    >
                                        {status === "loading" ? "AUTHENTICATING..." : authMode === "login" ? "SIGN IN" : "CREATE ACCOUNT"}
                                    </button>

                                    <div className="flex justify-center mt-6">
                                        <button
                                            type="button"
                                            onClick={() => setAuthMode(authMode === "login" ? "signup" : "login")}
                                            className="text-[9px] uppercase tracking-[0.3em] text-neutral-500 hover:text-emerald-400 transition-colors font-black"
                                        >
                                            {authMode === "login" ? "[ Create New Account ]" : "[ Sign In to Existing Account ]"}
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}
                    </div>
                )}

                {/* Inline error box removed. Relying on global Toast notifications. */}
            </main>
        </div>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { gsap } from "gsap";
import { useGSAP } from "@gsap/react";
import ScrollController from "@/components/ScrollController";
import PDFUploader from "@/components/PDFUploader";
import RedactionPreview from "@/components/RedactionPreview";
import AIInterface from "@/components/AIInterface";
import BiddingEditor from "@/components/BiddingEditor";
import TalentSearch from "@/components/TalentSearch";
import MissionDeployment from "@/components/MissionDeployment";
import { ArrowUpRight, Shield, Zap, Globe } from "lucide-react";
import { useUserStore } from "@/lib/userStore";
import { createClient } from "@/utils/supabase/client";

interface Mission {
  id: string;
  title: string;
}

export default function Home() {
  const containerRef = useRef<HTMLDivElement>(null);
  const { role, isAuthenticated } = useUserStore();
  const [mounted, setMounted] = useState(false);
  const [activeMission, setActiveMission] = useState<Mission | null>(null);
  const supabase = createClient();

  useEffect(() => {
    setMounted(true);

    // Fetch latest active mission for bidding display
    const fetchMission = async () => {
      const { data } = await supabase
        .from('missions')
        .select('id, title')
        .eq('status', 'active')
        .order('created_at', { ascending: false })
        .limit(1)
        .single();

      if (data) setActiveMission(data);
    };

    fetchMission();
  }, []);

  useGSAP(() => {
    const tl = gsap.timeline({ defaults: { ease: "expo.out" } });

    tl.fromTo(".hero-animate",
      { y: 60, opacity: 0 },
      { y: 0, opacity: 1, stagger: 0.15, duration: 2, delay: 0.5 }
    );

    tl.fromTo(".shimmer-bar",
      { width: 0 },
      { width: "100%", duration: 1.5, ease: "power4.inOut" },
      "-=1.5"
    );
  }, { scope: containerRef });

  if (!mounted) return null;

  const isOrg = role === 'organization';
  const accentColor = isOrg ? "blue-500" : "emerald-500";
  const accentText = isOrg ? "text-blue-500" : "text-emerald-500";
  const accentBorder = isOrg ? "border-blue-500/50" : "border-emerald-500/50";
  const accentBg = isOrg ? "bg-blue-500" : "bg-emerald-500";
  const accentShadow = isOrg ? "shadow-blue-500/20" : "shadow-emerald-500/20";

  return (
    <main ref={containerRef} className="relative min-h-screen w-full overflow-hidden">
      <ScrollController />

      <AIInterface />

      {/* Persistent HUD Layers - Conditional based on role */}
      <div className="fixed bottom-8 left-8 z-30 pointer-events-auto hero-animate">
        {isOrg ? (
          <TalentSearch />
        ) : (
          <BiddingEditor missionId={activeMission?.id} />
        )}
      </div>

      <div className="fixed bottom-8 right-8 z-30 flex flex-col items-end gap-6 pointer-events-auto hero-animate">
        {isOrg ? (
          <MissionDeployment />
        ) : (
          <>
            <PDFUploader />
            <RedactionPreview />
          </>
        )}
      </div>

      {/* Hero Content Layer */}
      <div className="relative z-20 flex flex-col justify-start items-center text-center min-h-screen p-8 lg:p-12 pt-20 lg:pt-28 pointer-events-none pb-48">
        <div className="max-w-4xl space-y-6 flex flex-col items-center">
          <div className="space-y-2 hero-animate w-full flex flex-col items-center">
            <span className={`${accentText} font-mono text-[10px] tracking-[0.5em] uppercase font-black opacity-80 flex items-center justify-center gap-3 w-full`}>
              <Zap className={`w-3 h-3 fill-current`} /> {isOrg ? "MANAGEMENT ACTIVE" : "SYSTEM ACTIVE"}
            </span>
            <div className={`h-[1px] mx-auto shimmer-bar bg-gradient-to-r from-transparent via-${isOrg ? 'blue' : 'emerald'}-500/50 to-transparent w-full max-w-sm`} />
          </div>

          <div className="hero-animate">
            <h1 className="text-6xl md:text-7xl lg:text-8xl font-black tracking-tighter text-white leading-[0.85] font-outfit uppercase">
              Vasudha
            </h1>
          </div>

          <div className="hero-animate max-w-lg mx-auto">
            <p className="text-neutral-400 text-sm md:text-base lg:text-lg font-medium leading-relaxed font-inter opacity-70">
              {isOrg
                ? "The premier platform for business growth. Post projects, browse global talent, and hire experts."
                : "The next-generation freelance ecosystem. Real-time project search, secure contracts, and verified talent directories."
              }
            </p>
          </div>

          <div className="flex flex-wrap gap-4 items-center justify-center hero-animate pointer-events-auto mt-6">
            {!isAuthenticated && (
              <Link
                href="/login"
                className="group relative px-8 py-4 bg-white text-black font-black text-[10px] md:text-xs uppercase tracking-[0.2em] transition-all hover:scale-105 active:scale-95 shadow-[0_0_30px_rgba(255,255,255,0.1)] rounded-sm font-outfit overflow-hidden"
              >
                <span className="relative z-10 flex items-center gap-3">
                  Sign Up Now <ArrowUpRight className="w-4 h-4 transition-transform group-hover:translate-x-1 group-hover:-translate-y-1" />
                </span>
                <div className={`absolute inset-x-0 bottom-0 h-0 ${accentBg} transition-all group-hover:h-1`} />
              </Link>
            )}

            <div className="flex items-center gap-8 px-8 py-3 glass-panel border border-white/5 rounded-full backdrop-blur-3xl shadow-2xl">
              <div className="flex items-center gap-3">
                <Shield className={`w-4 h-4 ${isOrg ? 'text-blue-500' : 'text-emerald-500'}`} />
                <span className="text-[10px] text-neutral-400 font-black uppercase tracking-widest font-mono">Secure</span>
              </div>
              <div className="w-[1px] h-4 bg-white/10" />
              <div className="flex items-center gap-3">
                <Globe className={`w-4 h-4 ${isOrg ? 'text-blue-400' : 'text-blue-500'}`} />
                <span className="text-[10px] text-neutral-400 font-black uppercase tracking-widest font-mono">Global</span>
              </div>
            </div>
          </div>
        </div>
      </div>

    </main>
  );
}

"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/utils/supabase/client";
import { Loader2, ShieldAlert, LogOut } from "lucide-react";
import Navigation from "@/components/ui/Navigation";
import SceneWrapper from "@/components/canvas/SceneWrapper";
import FreelancerProfile from "@/components/profile/FreelancerProfile";
import OrganizationProfile from "@/components/profile/OrganizationProfile";
import { useRouter } from "next/navigation";

export default function ProfilePage() {
    const [loading, setLoading] = useState(true);
    const [profile, setProfile] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);
    const supabase = createClient();
    const router = useRouter();

    useEffect(() => {
        async function fetchProfile() {
            try {
                const { data: { user } } = await supabase.auth.getUser();
                if (!user) {
                    router.push("/login");
                    return;
                }

                const { data, error: profileError } = await supabase
                    .from("profiles")
                    .select("*")
                    .eq("id", user.id)
                    .single();

                if (profileError) throw profileError;
                setProfile(data);
            } catch (err: any) {
                console.error("Profile fetch error:", err);
                setError(err.message);
            } finally {
                setLoading(false);
            }
        }

        fetchProfile();
    }, [supabase, router]);

    const handleSignOut = async () => {
        await supabase.auth.signOut();
        router.push("/");
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-[#030305] flex flex-col items-center justify-center p-6 text-center">
                <Loader2 className="w-12 h-12 text-emerald-500 animate-spin mb-6" />
                <h1 className="text-xl font-bold text-white uppercase tracking-[0.5em] font-outfit">Loading Profile</h1>
            </div>
        );
    }

    if (error) {
        return (
            <div className="min-h-screen bg-[#030305] flex flex-col items-center justify-center p-6 text-center">
                <div className="w-20 h-20 rounded-full bg-rose-500/10 flex items-center justify-center mb-8 border border-rose-500/20">
                    <ShieldAlert className="w-10 h-10 text-rose-500" />
                </div>
                <h1 className="text-2xl font-black text-white uppercase tracking-tighter mb-4 font-outfit">Connection Error</h1>
                <p className="text-neutral-400 max-w-md mb-10 leading-relaxed">{error}</p>
                <button
                    onClick={() => window.location.reload()}
                    className="px-8 py-3 bg-white text-black font-black uppercase text-xs tracking-widest hover:bg-emerald-500 transition-colors"
                >
                    Retry Connection
                </button>
            </div>
        );
    }

    return (
        <main className="relative min-h-screen bg-[#030305] overflow-x-hidden pt-32 pb-20">
            <Navigation />
            <SceneWrapper />

            {/* Background Atmosphere */}
            <div className="fixed inset-0 z-0 bg-[radial-gradient(circle_at_60%_40%,_rgba(16,185,129,0.05),_transparent_50%)] pointer-events-none" />
            <div className="fixed inset-0 z-0 bg-[radial-gradient(circle_at_40%_60%,_rgba(59,130,246,0.05),_transparent_50%)] pointer-events-none" />

            <div className="relative z-10 container mx-auto px-6">
                <div className="flex justify-end mb-12">
                    <button
                        onClick={handleSignOut}
                        className="group flex items-center gap-3 px-6 py-2.5 bg-rose-500/10 border border-rose-500/20 rounded-full text-rose-300 text-xs font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all"
                    >
                        Sign Out <LogOut className="w-3.5 h-3.5 group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>

                {profile?.role === "freelancer" ? (
                    <FreelancerProfile data={profile} />
                ) : profile?.role === "organization" ? (
                    <OrganizationProfile data={profile} />
                ) : (
                    <div className="text-center py-20 text-neutral-500 uppercase tracking-widest text-xs font-black">
                        Loading account data...
                    </div>
                )}
            </div>
        </main>
    );
}

"use client";

import { Zap, Activity, ShieldCheck, Globe } from "lucide-react";
import { gsap } from "gsap";
import { useGSAP } from "@gsap/react";
import { useRef } from "react";

export default function MissionDeployment() {
    const containerRef = useRef<HTMLDivElement>(null);

    useGSAP(() => {
        gsap.fromTo(".mission-panel",
            { y: 20, opacity: 0 },
            { y: 0, opacity: 1, duration: 0.8, stagger: 0.15, ease: "back.out(1.2)" }
        );
    }, { scope: containerRef });

    return (
        <div ref={containerRef} className="space-y-4 w-72">
            <div className="mission-panel glass-panel p-5 border-blue-500/20 bg-blue-500/[0.02]">
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <Zap className="w-4 h-4 text-blue-400 animate-pulse" />
                        <span className="text-[10px] text-white font-black uppercase tracking-[0.2em]">Project HUD</span>
                    </div>
                    <div className="px-2 py-0.5 rounded-full bg-blue-500/20 border border-blue-500/30">
                        <span className="text-[8px] text-blue-300 font-bold uppercase tracking-tight">Active</span>
                    </div>
                </div>

                <div className="space-y-4">
                    <div className="flex items-center gap-4">
                        <div className="flex-1">
                            <div className="flex justify-between mb-1">
                                <span className="text-[9px] text-neutral-500 uppercase font-bold">Signal Strength</span>
                                <span className="text-[9px] text-blue-400 font-mono tracking-tighter">98.2%</span>
                            </div>
                            <div className="h-1 bg-white/5 rounded-full overflow-hidden">
                                <div className="h-full bg-blue-500 w-[98%] shadow-[0_0_8px_rgba(59,130,246,0.5)]" />
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3 pt-2">
                        <div className="p-3 bg-white/[0.02] border border-white/5 rounded-sm">
                            <span className="block text-[8px] text-neutral-500 uppercase font-bold mb-1">Uptime</span>
                            <span className="text-xs text-white font-mono font-bold">99.99%</span>
                        </div>
                        <div className="p-3 bg-white/[0.02] border border-white/5 rounded-sm">
                            <span className="block text-[8px] text-neutral-500 uppercase font-bold mb-1">Latency</span>
                            <span className="text-xs text-blue-400 font-mono font-bold">12ms</span>
                        </div>
                    </div>
                </div>
            </div>

            <button className="mission-panel w-full py-4 glass-panel border border-blue-500/30 hover:bg-blue-500/10 transition-all text-white font-black text-[10px] uppercase tracking-[0.3em] flex items-center justify-center gap-3 group">
                <Globe className="w-3 h-3 text-blue-400 group-hover:rotate-180 transition-transform duration-700" />
                Post Project
            </button>
        </div>
    );
}

"use client";

import { Search, Filter, TrendingUp, Users } from "lucide-react";
import { gsap } from "gsap";
import { useGSAP } from "@gsap/react";
import { useRef } from "react";

export default function TalentSearch() {
    const containerRef = useRef<HTMLDivElement>(null);

    useGSAP(() => {
        gsap.fromTo(".talent-panel",
            { x: 50, opacity: 0 },
            { x: 0, opacity: 1, duration: 1, stagger: 0.1, ease: "power3.out" }
        );
    }, { scope: containerRef });

    return (
        <div ref={containerRef} className="space-y-4 w-80">
            {/* Search Module */}
            <div className="talent-panel glass-panel p-4 border-blue-500/20">
                <div className="flex items-center gap-3 mb-4">
