import { useRef, useMemo } from "react";
import { useFrame, ThreeEvent } from "@react-three/fiber";
import * as THREE from "three";
import { useExploreStore, JobNode, FreelancerNode } from "@/lib/exploreStore";
import { useUserStore } from "@/lib/userStore";

const CLUSTER_COUNT = 4; // 4 categories
const STARS_PER_CLUSTER = 800;
const TOTAL_STARS = CLUSTER_COUNT * STARS_PER_CLUSTER;

const clusterCenters = [
    new THREE.Vector3(20, 10, -30),
    new THREE.Vector3(-25, -15, -40),
    new THREE.Vector3(15, -20, -20),
    new THREE.Vector3(-10, 25, -50),
];

const categories: ('frontend' | 'backend' | 'ai' | 'design')[] = ['frontend', 'backend', 'ai', 'design'];
const budgets: ('low' | 'medium' | 'high')[] = ['low', 'medium', 'high'];
const levels = ['Junior', 'Mid-Level', 'Senior', 'Lead'];

export default function NexusConstellations() {
    const meshRef = useRef<THREE.InstancedMesh>(null);
    const { setHoveredJob, setSelectedJob, setHoveredFreelancer, setSelectedFreelancer, setCameraTarget } = useExploreStore();
    const { role } = useUserStore();

    const isOrg = role === 'organization';

    const { data, colorArray } = useMemo(() => {
        const nodes: (JobNode | FreelancerNode)[] = [];
        const colors = new Float32Array(TOTAL_STARS * 3);
        const color = new THREE.Color();

        for (let c = 0; c < CLUSTER_COUNT; c++) {
            const center = clusterCenters[c];
            const category = categories[c];

            for (let i = 0; i < STARS_PER_CLUSTER; i++) {
                const index = c * STARS_PER_CLUSTER + i;
                const r = Math.pow(Math.random(), 3) * 15;
                const theta = Math.random() * Math.PI * 2;
                const phi = Math.acos(2 * Math.random() - 1);

                const x = center.x + r * Math.sin(phi) * Math.cos(theta);
                const y = center.y + r * Math.sin(phi) * Math.sin(theta);
                const z = center.z + r * Math.cos(phi);
                const position = new THREE.Vector3(x, y, z);

                if (isOrg) {
                    const level = levels[Math.floor(Math.random() * levels.length)];
                    nodes.push({
                        id: index,
                        name: `Freelancer ${index.toString(16).toUpperCase()}`,
                        role: `${level} ${category.charAt(0).toUpperCase() + category.slice(1)} Engineer`,
                        level,
                        category,
                        position
                    } as FreelancerNode);
                } else {
                    const budget = budgets[Math.floor(Math.random() * budgets.length)];
                    nodes.push({
                        id: index,
                        title: `Project ${index.toString(16).toUpperCase()}`,
                        category,
                        budget,
                        position
                    } as JobNode);
                }

                // Color based on category
                if (category === 'frontend') color.setHex(0x3b82f6); // Blue
                else if (category === 'backend') color.setHex(0x10b981); // Emerald
                else if (category === 'ai') color.setHex(0xa855f7); // Purple
                else if (category === 'design') color.setHex(0xf59e0b); // Amber
                color.toArray(colors, index * 3);
            }
        }
        return { data: nodes, colorArray: colors };
    }, [isOrg]);

    useMemo(() => {
        if (!meshRef.current) return;
        const dummy = new THREE.Object3D();
        data.forEach((node, i) => {
            dummy.position.copy(node.position);
            const scale = Math.random() * 0.5 + 0.1;
            dummy.scale.set(scale, scale, scale);
            dummy.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI);
            dummy.updateMatrix();
            meshRef.current!.setMatrixAt(i, dummy.matrix);
        });
        meshRef.current.instanceMatrix.needsUpdate = true;
    }, [data]);

    useFrame((state) => {
        if (meshRef.current) meshRef.current.rotation.y += 0.0002;
        const currentTarget = useExploreStore.getState().cameraTarget;
        if (currentTarget) {
            const offsetTarget = currentTarget.clone().add(new THREE.Vector3(0, 0, 5));
            state.camera.position.lerp(offsetTarget, 0.05);
            state.camera.lookAt(currentTarget);
        } else {
            state.camera.position.x = Math.sin(state.clock.elapsedTime * 0.1) * 2;
            state.camera.position.y = Math.cos(state.clock.elapsedTime * 0.1) * 2;
            state.camera.lookAt(0, 0, -30);
        }
    });

    const handlePointerOver = (e: ThreeEvent<PointerEvent>) => {
        e.stopPropagation();
        document.body.style.cursor = 'pointer';
        const instanceId = e.instanceId;
        if (instanceId !== undefined) {
            if (isOrg) setHoveredFreelancer(data[instanceId] as FreelancerNode);
            else setHoveredJob(data[instanceId] as JobNode);
        }
    };

    const handlePointerOut = () => {
        document.body.style.cursor = 'auto';
        setHoveredJob(null);
        setHoveredFreelancer(null);
    };

    const handleClick = (e: ThreeEvent<MouseEvent>) => {
        e.stopPropagation();
        const instanceId = e.instanceId;
        if (instanceId !== undefined) {
            const node = data[instanceId];
            if (isOrg) setSelectedFreelancer(node as FreelancerNode);
            else setSelectedJob(node as JobNode);

            if (meshRef.current) {
                const worldPos = node.position.clone();
                worldPos.applyEuler(meshRef.current.rotation);
                setCameraTarget(worldPos);
            }
        }
    };

    return (
        <instancedMesh
            ref={meshRef}
            args={[null as any, null as any, TOTAL_STARS]}
            onPointerOver={handlePointerOver}
            onPointerOut={handlePointerOut}
            onClick={handleClick}
        >
            <icosahedronGeometry args={[1, 0]}>
                <instancedBufferAttribute attach="attributes-color" args={[colorArray, 3]} />
            </icosahedronGeometry>
            <meshStandardMaterial vertexColors roughness={0.2} transparent opacity={0.9} />
        </instancedMesh>
    );
}

"use client";

import { useRef, useMemo } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { MeshDistortMaterial, Float, Points, PointMaterial } from "@react-three/drei";
import { useUserStore } from "@/lib/userStore";

export default function NexusCore3D({ reduced = false }: { reduced?: boolean }) {
    const { role } = useUserStore();
    const isOrg = role === 'organization';

    const coreRef = useRef<THREE.Mesh>(null);
    const wireframeRef = useRef<THREE.Mesh>(null);
    const pointsRef = useRef<THREE.Points>(null);

    const primaryColor = isOrg ? "#3b82f6" : "#10b981"; // Blue or Emerald
    const secondaryColor = isOrg ? "#8b5cf6" : "#059669"; // Purple or darker Emerald

    // Generate random particles for the surrounding nebula
    const [positions] = useMemo(() => {
        const count = reduced ? 800 : 3000;
        const positions = new Float32Array(count * 3);
        for (let i = 0; i < count; i++) {
            const r = reduced ? 8 + Math.random() * 15 : 12 + Math.random() * 25; 
            const theta = 2 * Math.PI * Math.random();
            const phi = Math.acos(2 * Math.random() - 1);

            const x = r * Math.sin(phi) * Math.cos(theta);
            const y = r * Math.sin(phi) * Math.sin(theta);
            const z = r * Math.cos(phi);

            positions[i * 3] = x;
            positions[i * 3 + 1] = y;
            positions[i * 3 + 2] = z;
        }
        return [positions];
    }, []);

    useFrame((state) => {
        const t = state.clock.getElapsedTime();

        // Morphing inner core rotation
        if (coreRef.current) {
            coreRef.current.rotation.y = t * 0.15;
            coreRef.current.rotation.x = t * 0.1;
        }

        // Counter-rotating outer wireframe
        if (wireframeRef.current) {
            wireframeRef.current.rotation.y = -t * 0.1;
            wireframeRef.current.rotation.z = t * 0.05;
        }

        // Slow particle orbit
        if (pointsRef.current) {
            pointsRef.current.rotation.y = t * 0.03;
            pointsRef.current.rotation.x = t * 0.01;
        }
    });

    return (
        <group position={[0, 0, -35]}>
            {/* Inner dynamic morphing core */}
            <Float speed={1.5} rotationIntensity={0.5} floatIntensity={1}>
                <mesh ref={coreRef}>
                    <icosahedronGeometry args={[6, 4]} />
                    <MeshDistortMaterial
                        color={primaryColor}
                        emissive={primaryColor}
                        emissiveIntensity={0.4}
                        wireframe={false}
                        distort={0.3}
                        speed={2}
                        roughness={0.2}
                        metalness={0.8}
                        transparent
                        opacity={0.8}
                    />
                </mesh>
            </Float>

            {/* Outer geometric wireframe shell */}
            <mesh ref={wireframeRef}>
                <icosahedronGeometry args={[9, 1]} />
                <meshStandardMaterial
                    color={secondaryColor}
                    wireframe={true}
                    transparent
                    opacity={0.15}
                    emissive={secondaryColor}
                    emissiveIntensity={0.8}
                />
            </mesh>

            {/* Surrounding particle nebula */}
            <Points ref={pointsRef} positions={positions} stride={3}>
                <PointMaterial
                    transparent
                    color={primaryColor}
                    size={0.12}
                    sizeAttenuation={true}
                    depthWrite={false}
                    opacity={0.4}
                    blending={THREE.AdditiveBlending}
                />
            </Points>

            {/* Ambient Lighting for the core to pop against the dark background */}
            <pointLight position={[0, 0, 0]} intensity={3} color={primaryColor} distance={60} />
            <ambientLight intensity={0.1} />
        </group>
    );
}

"use client";

import { Activity, CheckCircle2, Clock, XCircle, Search, Filter, Loader2 } from "lucide-react";
import { useEffect, useState, useRef } from "react";
import { gsap } from "gsap";
import { createClient } from "@/utils/supabase/client";

interface Contract {
    id: string;
    client: string;
    role: string;
    status: 'pending' | 'reviewing' | 'active' | 'rejected';
    time: string;
    budget: string;
}

export default function ContractTracker() {
    const [contracts, setContracts] = useState<Contract[]>([]);
    const [loading, setLoading] = useState(true);
    const listRef = useRef<HTMLDivElement>(null);
    const supabase = createClient();

    useEffect(() => {
        const fetchBids = async () => {
            try {
                // Fetch bids and join with missions
                const { data, error } = await supabase
                    .from('bids')
                    .select(`
                        id,
                        proposal,
                        match_score,
                        created_at,
                        missions (
                            title,
                            id
                        )
                    `)
                    .order('created_at', { ascending: false });

                if (error) throw error;

                const formatted: Contract[] = (data || []).map((bid: any) => ({
                    id: bid.id.substring(0, 8).toUpperCase(),
                    client: 'Vasudha Market', // Placeholder for org name
                    role: bid.missions?.title || 'Unknown Project',
                    status: bid.match_score > 0.8 ? 'reviewing' : 'pending',
                    time: new Date(bid.created_at).toLocaleDateString(),
                    budget: '₹₹₹'
                }));

                setContracts(formatted);
            } catch (err) {
                console.error("Error fetching bids:", err);
            } finally {
                setLoading(false);
            }
        };

        fetchBids();
    }, [supabase]);

    const getStatusIcon = (status: Contract['status']) => {
        switch (status) {
            case 'pending': return <Activity className="w-3.5 h-3.5 text-blue-400 animate-pulse" />;
            case 'reviewing': return <Clock className="w-3.5 h-3.5 text-amber-400" />;
            case 'active': return <CheckCircle2 className="w-3.5 h-3.5 text-emerald-400" />;
            case 'rejected': return <XCircle className="w-3.5 h-3.5 text-neutral-600" />;
        }
    };

    const getStatusText = (status: Contract['status']) => {
        return status.toUpperCase();
    };

    return (
        <div className="glass-panel w-full p-10 border border-white/5 rounded-2xl shadow-2xl backdrop-blur-3xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-emerald-500/20 to-transparent" />

            <div className="flex justify-between items-center mb-10 relative z-10">
                <div className="space-y-1">
                    <h2 className="text-white text-xs tracking-[0.4em] uppercase font-black opacity-50">Work History</h2>
                    <h3 className="text-white text-xl font-bold font-outfit uppercase tracking-tighter">Active Contracts</h3>
                </div>

                <div className="flex items-center gap-3">
                    <button className="p-2.5 bg-white/5 hover:bg-white/10 border border-white/5 rounded-full transition-all text-neutral-400 hover:text-white">
                        <Search className="w-3.5 h-3.5" />
                    </button>
                    <button className="p-2.5 bg-white/5 hover:bg-white/10 border border-white/5 rounded-full transition-all text-neutral-400 hover:text-white">
                        <Filter className="w-3.5 h-3.5" />
                    </button>
                </div>
            </div>

            {loading ? (
                <div className="flex flex-col items-center justify-center py-20 animate-pulse">
                    <Loader2 className="w-8 h-8 text-blue-500 animate-spin mb-4" />
                    <span className="text-[10px] text-neutral-500 uppercase tracking-widest font-black">Loading Projects...</span>
                </div>
            ) : (
                <div ref={listRef} className="flex flex-col gap-4 relative z-10">
                    {contracts.length === 0 ? (
                        <div className="text-center py-10 text-neutral-500 uppercase tracking-widest text-[10px] font-black italic">
                            No active projects detected in this category.
                        </div>
                    ) : contracts.map((contract) => (
                        <div
                            key={contract.id}
                            className="grid grid-cols-12 gap-4 items-center p-5 bg-white/[0.01] border border-white/5 hover:border-white/10 hover:bg-white/[0.03] transition-all duration-500 rounded-xl cursor-pointer group"
                        >
                            {/* Status */}
                            <div className="col-span-2 md:col-span-1 flex flex-col items-center justify-center border-r border-white/5">
                                {getStatusIcon(contract.status)}
                                <span className={`text-[6px] font-black tracking-widest mt-2 ${contract.status === 'active' ? 'text-emerald-500' :
                                        contract.status === 'pending' ? 'text-blue-500' :
                                            contract.status === 'reviewing' ? 'text-amber-500' : 'text-neutral-600'
                                    }`}>
                                    {getStatusText(contract.status)}
                                </span>
                            </div>

                            {/* Details */}
                            <div className="col-span-10 md:col-span-5 flex flex-col justify-center">
                                <span className="text-white font-bold text-sm tracking-tight group-hover:text-emerald-400 transition-colors duration-500 font-outfit">{contract.role}</span>
                                <span className="text-neutral-500 text-[10px] uppercase tracking-widest font-black mt-1 opacity-60 group-hover:opacity-100 transition-opacity font-mono">{contract.client}</span>
                            </div>

                            {/* ID */}
                            <div className="hidden md:flex col-span-3 items-center justify-center">
                                <span className="px-3 py-1 bg-white/5 border border-white/5 rounded-full text-neutral-500 font-mono text-[9px] tracking-widest uppercase">
                                    {contract.id}
                                </span>
                            </div>

                            {/* Budget & Time */}
                            <div className="hidden md:flex flex-col col-span-3 items-end">
                                <span className="text-white font-black font-outfit text-sm group-hover:text-emerald-400 transition-colors uppercase tracking-tighter">{contract.budget}</span>
                                <span className="text-neutral-600 font-mono text-[9px] uppercase tracking-widest mt-1">{contract.time}</span>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            <button className="w-full mt-10 py-5 border-t border-white/5 text-neutral-500 hover:text-emerald-400 text-[9px] font-black uppercase tracking-[0.4em] transition-all group">
                Access Archives <span className="inline-block transition-transform group-hover:translate-x-2">&rarr;</span>
            </button>
        </div>
    );
}

